import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        reverseAdj[v].push([u, w]);
    }

    // dist[u][0] = cost to reach u without using any switch
    // dist[u][1] = cost to reach u with using a switch
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] = 0;

    const pq = new MinPriorityQueue({ priority: (x) => x.cost });
    pq.enqueue({ node: 0, used: 0, cost: 0 });

    while (!pq.isEmpty()) {
        const { node: u, used, cost } = pq.dequeue().element;
        if (u === n - 1) {
            return cost;
        }
        if (cost > dist[u][used]) {
            continue;
        }

        // Normal edges
        for (const [v, w] of adj[u]) {
            if (cost + w < dist[v][used]) {
                dist[v][used] = cost + w;
                pq.enqueue({ node: v, used, cost: dist[v][used] });
            }
        }

        // If not used switch yet, try to use it
        if (used === 0) {
            for (const [v, w] of reverseAdj[u]) {
                const newCost = cost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    pq.enqueue({ node: v, used: 1, cost: newCost });
                }
            }
        }
    }

    const res = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return res === Infinity ? -1 : res;
}

