		dist[i][0] = 1 << 60
		dist[i][1] = 1 << 60
	}
	dist[0][0] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{node: 0, used: 0, cost: 0})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		u, used, cost := item.node, item.used, item.cost
		if u == int(n-1) {
